@dataclass
class DocumentChunk:
    doc_id: str
    source: str
    chunk_id: int
    text: str
    metadata: Dict


class SQLiteVectorStore:
    def __init__(self, db_path: str = "rag_store.db"):
        self.db_path = db_path
        self.conn = sqlite3.connect(self.db_path)
        self.conn.execute("PRAGMA journal_mode=WAL;")
        self._create_tables()

    def _create_tables(self):
        self.conn.execute("""
            CREATE TABLE IF NOT EXISTS documents (
                id TEXT PRIMARY KEY,
                source TEXT NOT NULL,
                chunk_id INTEGER NOT NULL,
                text TEXT NOT NULL,
                metadata TEXT,
                embedding TEXT NOT NULL
            )
        """)
        self.conn.execute("CREATE INDEX IF NOT EXISTS idx_documents_source ON documents(source)")
        self.conn.commit()

    def upsert_documents(self, chunks: List[DocumentChunk], embeddings: np.ndarray):
        rows = []
        for chunk, emb in zip(chunks, embeddings):
            rows.append((
                chunk.doc_id,
                chunk.source,
                chunk.chunk_id,
                chunk.text,
                json.dumps(chunk.metadata),
                json.dumps(emb.tolist())
            ))
        self.conn.executemany("""
            INSERT OR REPLACE INTO documents (id, source, chunk_id, text, metadata, embedding)
            VALUES (?, ?, ?, ?, ?, ?)
        """, rows)
        self.conn.commit()

    def delete_by_source(self, source: str):
        self.conn.execute("DELETE FROM documents WHERE source = ?", (source,))
        self.conn.commit()

    def all_documents(self) -> List[Tuple[str, str, int, str, str, str]]:
        cur = self.conn.cursor()
        cur.execute("SELECT id, source, chunk_id, text, metadata, embedding FROM documents")
        return cur.fetchall()

    def similarity_search(self, query_embedding: np.ndarray, top_k: int = 5) -> List[Dict]:
        docs = self.all_documents()
        results = []
        q = self._normalize(query_embedding)

        for doc_id, source, chunk_id, text, metadata, embedding_json in docs:
            emb = np.array(json.loads(embedding_json), dtype=np.float32)
            emb = self._normalize(emb)
            score = float(np.dot(q, emb))
            results.append({
                "id": doc_id,
                "source": source,
                "chunk_id": chunk_id,
                "text": text,
                "metadata": json.loads(metadata) if metadata else {},
                "score": score
            })

        results.sort(key=lambda x: x["score"], reverse=True)
        return results[:top_k]

    @staticmethod
    def _normalize(vec: np.ndarray) -> np.ndarray:
        norm = np.linalg.norm(vec)
        if norm == 0:
            return vec
        return vec / norm

    def close(self):
        self.conn.close()


class Embedder:
    def __init__(self, model_name: str = "all-MiniLM-L6-v2"):
        self.model = SentenceTransformer(model_name)

    def embed_texts(self, texts: List[str]) -> np.ndarray:
        return np.array(self.model.encode(texts, convert_to_numpy=True, normalize_embeddings=False), dtype=np.float32)

    def embed_query(self, text: str) -> np.ndarray:
        return np.array(self.model.encode([text], convert_to_numpy=True, normalize_embeddings=False)[0], dtype=np.float32)


class DocumentLoader:
    SUPPORTED_EXTENSIONS = {".txt", ".md", ".rst"}

    @staticmethod
    def load_file(path: str) -> str:
        with open(path, "r", encoding="utf-8", errors="ignore") as f:
            return f.read()

    @classmethod
    def load_directory(cls, directory: str) -> List[Tuple[str, str]]:
        docs = []
        for root, _, files in os.walk(directory):
            for name in files:
                ext = os.path.splitext(name)[1].lower()
                if ext in cls.SUPPORTED_EXTENSIONS:
                    full_path = os.path.join(root, name)
                    text = cls.load_file(full_path)
                    docs.append((full_path, text))
        return docs


class TextChunker:
    def __init__(self, chunk_size: int = 800, chunk_overlap: int = 150):
        self.chunk_size = chunk_size
        self.chunk_overlap = chunk_overlap

    def chunk_text(self, source: str, text: str) -> List[DocumentChunk]:
        text = self._clean_text(text)
        if not text:
            return []

        chunks = []
        start = 0
        chunk_id = 0
        text_len = len(text)

        while start < text_len:
            end = min(start + self.chunk_size, text_len)
            if end < text_len:
                split = text.rfind("\n", start, end)
                if split == -1:
                    split = text.rfind(" ", start, end)
                if split > start + int(self.chunk_size * 0.5):
                    end = split

            chunk_text = text[start:end].strip()
            if chunk_text:
                doc_id = self._make_chunk_id(source, chunk_id, chunk_text)
                chunks.append(DocumentChunk(
                    doc_id=doc_id,
                    source=source,
                    chunk_id=chunk_id,
                    text=chunk_text,
                    metadata={"source": source, "chunk_id": chunk_id}
                ))
                chunk_id += 1

            if end >= text_len:
                break
            start = max(end - self.chunk_overlap, start + 1)

        return chunks

    @staticmethod
    def _make_chunk_id(source: str, chunk_id: int, text: str) -> str:
        h = hashlib.sha256(f"{source}:{chunk_id}:{text}".encode("utf-8")).hexdigest()
        return h

    @staticmethod
    def _clean_text(text: str) -> str:
        lines = [line.rstrip() for line in text.splitlines()]
        return "\n".join(lines).strip()


class RAGSystem:
    def __init__(
        self,
        db_path: str = "rag_store.db",
        embedding_model: str = "all-MiniLM-L6-v2",
        openai_model: str = "gpt-4o-mini"
    ):
        self.store = SQLiteVectorStore(db_path=db_path)
        self.embedder = Embedder(model_name=embedding_model)
        self.chunker = TextChunker()
        self.client = OpenAI(api_key=os.environ.get("OPENAI_API_KEY"))
        self.openai_model = openai_model

    def index_directory(self, directory: str):
        documents = DocumentLoader.load_directory(directory)
        for source, text in documents:
            self.store.delete_by_source(source)
            chunks = self.chunker.chunk_text(source, text)
            if not chunks:
                continue
            embeddings = self.embedder.embed_texts([c.text for c in chunks])
            self.store.upsert_documents(chunks, embeddings)

    def retrieve(self, query: str, top_k: int = 5) -> List[Dict]:
        query_emb = self.embedder.embed_query(query)
        return self.store.similarity_search(query_emb, top_k=top_k)

    def build_prompt(self, query: str, retrieved_docs: List[Dict]) -> str:
        context_blocks = []
        for i, doc in enumerate(retrieved_docs, start=1):
            context_blocks.append(
                f"[Document {i}]\n"
                f"Source: {doc['source']}\n"
                f"Chunk: {doc['chunk_id']}\n"
                f"Relevance Score: {doc['score']:.4f}\n"
                f"Content:\n{doc['text']}"
            )

        context = "\n\n".join(context_blocks) if context_blocks else "No relevant documents found."

        prompt = (
            "You are an internal knowledge base assistant for the company.\n"
            "Answer the user's question using only the provided retrieved documents.\n"
            "If the answer is not contained in the documents, say you do not know based on the available internal knowledge.\n"
            "Cite the document source names in your answer when relevant.\n\n"
            "Retrieved Documents:\n"
            f"{context}\n\n"
            f"User Question: {query}\n\n"
            "Answer:"
        )
        return prompt

    def generate_answer(self, query: str, top_k: int = 5) -> Dict:
        retrieved_docs = self.retrieve(query, top_k=top_k)
        prompt = self.build_prompt(query, retrieved_docs)

        response = self.client.chat.completions.create(
            model=self.openai_model,
            messages=[
                {
                    "role": "system",
                    "content": "You answer internal company knowledge base questions using retrieved documents."
                },
                {
                    "role": "user",
                    "content": prompt
                }
            ],
            temperature=0.2
        )

        answer = response.choices[0].message.content
        return {
            "query": query,
            "answer": answer,
            "retrieved_documents": retrieved_docs,
            "prompt": prompt
        }

    def close(self):
        self.store.close()


def main():
    import argparse

    parser = argparse.ArgumentParser(description="Internal Knowledge Base RAG System")
    subparsers = parser.add_subparsers(dest="command", required=True)

    index_parser = subparsers.add_parser("index", help="Index documents from a directory")
    index_parser.add_argument("--docs-dir", required=True, help="Directory containing company documents")
    index_parser.add_argument("--db-path", default="rag_store.db")
    index_parser.add_argument("--embedding-model", default="all-MiniLM-L6-v2")

    ask_parser = subparsers.add_parser("ask", help="Ask a question")
    ask_parser.add_argument("--query", required=True, help="User query")
    ask_parser.add_argument("--top-k", type=int, default=5, help="Number of documents to retrieve")
    ask_parser.add_argument("--db-path", default="rag_store.db")
    ask_parser.add_argument("--embedding-model", default="all-MiniLM-L6-v2")
    ask_parser.add_argument("--openai-model", default="gpt-4o-mini")

    args = parser.parse_args()

    if args.command == "index":
        rag = RAGSystem(
            db_path=args.db_path,
            embedding_model=args.embedding_model
        )
        try:
            rag.index_directory(args.docs_dir)
            print(json.dumps({
                "status": "success",
                "message": f"Indexed documents from {args.docs_dir}"
            }, indent=2))
        finally:
            rag.close()

    elif args.command == "ask":
        rag = RAGSystem(
            db_path=args.db_path,
            embedding_model=args.embedding_model,
            openai_model=args.openai_model
        )
        try:
            result = rag.generate_answer(args.query, top_k=args.top_k)
            print(json.dumps(result, indent=2, ensure_ascii=False))
        finally:
            rag.close()


if __name__ == "__main__":
    main()